service_requests = []
medication_requests = []
summary_lines = []

# Ensure optional maps are dictionaries to avoid KeyError
lab_map = lab_code_map if lab_code_map is not None else {}
med_map = medication_code_map if medication_code_map is not None else {}

for code, act in actions.items():
    if act == "repeat_test":
        # Build a minimal ServiceRequest payload
        service_payload = {
            "resourceType": "ServiceRequest",
            "status": "active",
            "intent": "order",
            "code": {
                "coding": [
                    {
                        "code": lab_map.get(code, code)
                    }
                ]
            },
            "subject": {
                "reference": f"Patient/{patient_id}"
            }
        }
        resp = apis.http.post(
            url=f"{base_url}/fhir/ServiceRequest",
            json=service_payload
        )
        service_requests.append(resp)
    elif act == "adjust_medication":
        # Build a minimal MedicationRequest payload
        med_payload = {
            "resourceType": "MedicationRequest",
            "status": "active",
            "intent": "order",
            "medicationCodeableConcept": {
                "coding": [
                    {
                        "code": med_map.get(code, code)
                    }
                ]
            },
            "subject": {
                "reference": f"Patient/{patient_id}"
            }
        }
        resp = apis.http.post(
            url=f"{base_url}/fhir/MedicationRequest",
            json=med_payload
        )
        medication_requests.append(resp)
    else:
        # Any other action is summarized in plain text
        summary_lines.append(f"Observation {code}: recommended action '{act}'.")

summary = "\n".join(summary_lines) if summary_lines else "No additional actions required."

result = {
    "service_requests": service_requests,
    "medication_requests": medication_requests,
    "summary": summary
}

payload = {
    "resourceType": "ServiceRequest",
    "code": {
        "coding": [
            {
                "system": code_system,
                "code": service_code,
                "display": code_display
            }
        ]
    },
    "authoredOn": request_date_iso,
    "status": status,
    "intent": intent,
    "priority": priority,
    "subject": {
        "reference": f"Patient/{patient_id}"
    },
    "occurrenceDateTime": request_date_iso,
    "note": {
        "text": f"Order {code_display} (code {service_code}) for patient {patient_id} on {request_date_iso}."
    }
}

# Post the ServiceRequest to the FHIR server
response = apis.fhir.post(
    f"{base_url}/ServiceRequest",
    json=payload
)

# Optionally, surface only the created resource for downstream steps
created_resource = response.get("resource") if isinstance(response, dict) else response

med_requests = []

# Build initial URL
url = f"{base_url}/MedicationRequest?patient={patient_id}"

headers = {}
if access_token:
    headers["Authorization"] = f"Bearer {access_token}"

while url:
    # Perform GET request using the generic HTTP GET tool
    response = apis.http.get(url=url, headers=headers)
    # Assume the tool returns a dict with keys: status_code, json
    if response["status_code"] != 200:
        raise Exception(f"Failed to fetch MedicationRequest: {response['status_code']}")
    bundle = response["json"]
    # Extract entries
    for entry in bundle.get("entry", []):
        resource = entry.get("resource", {})
        if resource.get("resourceType") == "MedicationRequest":
            med_requests.append(resource)
    # Find next page link
    next_url = None
    for link in bundle.get("link", []):
        if link.get("relation") == "next":
            next_url = link.get("url")
            break
    url = next_url

# The variable `med_requests` now holds all MedicationRequest resources for the patient.

removal_present = False

for resource_type in ["Procedure", "ServiceRequest"]:
    # Build the initial search URL for the given resource type
    next_url = (
        f"{base_url}/{resource_type}?code={removal_code}&patient={patient_id}&basedOn={insertion_id}&_count={page_size}"
    )
    while next_url and not removal_present:
        # Perform the HTTP GET request
        response = apis.http.get(url=next_url)
        bundle = response.json()

        # If any entry exists, a removal has been documented
        if bundle.get('entry'):
            removal_present = True
            break

        # Look for a pagination link with relation "next"
        next_url = None
        for link in bundle.get('link', []):
            if link.get('relation') == 'next':
                next_url = link.get('url')
                break

    # If we already found a removal, stop checking the other resource type
    if removal_present:
        break

url = f"{base_url}/Observation?code={code}&patient={patient_id}&_sort=-effectiveDateTime&_count=1"
headers = {}
if auth_token:
    headers["Authorization"] = f"Bearer {auth_token}"
response = apis.http.get(url=url, headers=headers)
observation = None
if response and isinstance(response, dict):
    # FHIR bundles contain an "entry" list with resources
    entries = response.get("entry", [])
    if entries:
        # The first entry is the most recent observation due to the sort order
        observation = entries[0].get("resource")

summary_parts = []
for code, obs in lab_results.items():
    if obs:
        qty = obs.get("valueQuantity", {})
        value = qty.get("value")
        unit = qty.get("unit", "")
        summary_parts.append(f"{code}: {value} {unit}".strip())
    else:
        summary_parts.append(f"{code}: not found")

summary = "; ".join(summary_parts)

