while page_url:
    bundle = apis.fhir.get(url=page_url)
    for entry in bundle.get('entry', []):
        resource = entry.get('resource', {})
        if resource.get('resourceType') == 'Procedure':
            events.append(resource)
    # Look for the next page link
    next_link = None
    for link in bundle.get('link', []):
        if link.get('relation') == 'next':
            next_link = link.get('url')
            break
    page_url = next_link

# MedicationRequest side (COVID vaccine may be recorded as a medication request)
page_url = f"{base_url}/fhir/MedicationRequest?patient={patient_id}&code={','.join(vaccine_codes)}&_count=50"
while page_url:
    bundle = apis.fhir.get(url=page_url)
    for entry in bundle.get('entry', []):
        resource = entry.get('resource', {})
        if resource.get('resourceType') == 'MedicationRequest':
            events.append(resource)
    next_link = None
    for link in bundle.get('link', []):
        if link.get('relation') == 'next':
            next_link = link.get('url')
            break
    page_url = next_link

# Deduplicate by (resourceType, id)
unique = {}
for ev in events:
    key = (ev.get('resourceType'), ev.get('id'))
    if key not in unique:
        unique[key] = ev

events = list(unique.values())

# Normalise date field for sorting
def get_event_date(ev):
    if ev.get('resourceType') == 'Procedure':
        return ev.get('performedDateTime') or ev.get('occurrenceDateTime')
    if ev.get('resourceType') == 'MedicationRequest':
        return ev.get('authoredOn')
    return None

# Sort descending (most recent first)
events.sort(key=lambda e: get_event_date(e) or '', reverse=True)

records = []

# Helper to perform a GET request with optional auth
def _get(url):
    headers = {}
    if auth_token:
        headers["Authorization"] = f"Bearer {auth_token}"
    response = apis.http.get(url=url, headers=headers)
    # Assume the response object has a .json() method returning the FHIR bundle
    return response.json()

# 1. Retrieve MedicationRequest resources for the patient
med_url = f"{base_url}/MedicationRequest?patient={patient_id}"
while med_url:
    bundle = _get(med_url)
    for entry in bundle.get("entry", []):
        resource = entry.get("resource", {})
        # Keep only COVID‑19 vaccine requests (simple filter on medicationCodeableConcept)
        coding = resource.get("medicationCodeableConcept", {}).get("coding", [])
        if any(c.get("code") == "COVIDVACCINE" for c in coding):
            date = resource.get("authoredOn")
            records.append({
                "resource_type": "MedicationRequest",
                "date": date,
                "details": resource
            })
    # Follow pagination if present
    next_link = None
    for link in bundle.get("link", []):
        if link.get("relation") == "next":
            next_link = link.get("url")
            break
    med_url = next_link

# 2. Retrieve Procedure resources for the patient filtered by COVID‑19 vaccine code
proc_url = f"{base_url}/Procedure?patient={patient_id}&code=COVIDVACCINE"
while proc_url:
    bundle = _get(proc_url)
    for entry in bundle.get("entry", []):
        resource = entry.get("resource", {})
        date = resource.get("performedDateTime") or resource.get("performedPeriod", {}).get("start")
        records.append({
            "resource_type": "Procedure",
            "date": date,
            "details": resource
        })
    next_link = None
    for link in bundle.get("link", []):
        if link.get("relation") == "next":
            next_link = link.get("url")
            break
    proc_url = next_link

# 3. Sort records by date (most recent first)
records.sort(key=lambda r: r["date"] or "", reverse=True)

payload = {
    "resourceType": "ServiceRequest",
    "code": {
