# `response` now holds the supervisor's acknowledgement (or error) dictionary.

filtered_requests = []
for req in med_requests:
    # Check that the request is active
    if req.get("status") != "active":
        continue
    # Navigate to the medication code (supports both direct coding and reference lookup placeholders)
    med_concept = req.get("medicationCodeableConcept", {})
    codings = med_concept.get("coding", [])
    if not isinstance(codings, list):
        continue
    # Determine if any coding matches an opioid code
    is_opioid = False
    for coding in codings:
        code = coding.get("code")
        if isinstance(code, str) and code in opioid_codes:
            is_opioid = True
            break
    if is_opioid:
        filtered_requests.append(req)
# Result stored in filtered_requests

summary_messages = []

# 1. Summarize the procedure lookup result
if procedure_found:
