    summary_messages.append(
        f"Most recent CT Abdomen procedure was performed on {most_recent_date}."
    )
else:
    summary_messages.append(
        "No prior CT Abdomen procedure (IMGCT0491 or IMGIL0001) found for the patient."
    )

