    for link in bundle.get("link", []):
        if link.get("relation") == "next":
            next_link = link.get("url")
            break
    if not next_link:
        break
    # Prepare for the next iteration using the absolute URL provided by the server
    # The API wrapper expects the path portion only; strip domain if present
    if next_link.startswith("http"):
        # split on the first '/' after the scheme and host
        next_path = "/".join(next_link.split("/")[3:])
    else:
        next_path = next_link
    url = f"/{next_path}" if not next_path.startswith("/") else next_path
    # Reset params because pagination URL already contains all needed query values
    params = {}

# The variable ``records`` now holds all matching vaccination resources.

